   const db = new sqlite3.Database(':memory:'); // In-memory database for simplicity

   // Create a table to store form submissions
   db.serialize(() => {
       db.run("CREATE TABLE submissions (id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT, email TEXT, response TEXT)");
   });

   // Function to handle form submissions
   app.post('/submit', (req, res) => {
       const { name, email, response } = req.body;
       const sql = "INSERT INTO submissions (name, email, response) VALUES (?, ?, ?)";
       const values = [name, email, response];

       db.run(sql, values, function(err) {
           if (err) {
               console.error(err.message);
               res.status(500).json({ status: 'error', message: 'Failed to save submission' });
           } else {
               console.log(`New submission saved with ID: ${this.lastID}`);
               res.json({ status: 'success' });
           }
       });
   });

   // Close the database connection when the server stops
   app.on('close', () => {
       db.close((err) => {
           if (err) {
               console.error(err.message);
           }
           console.log('Database connection closed.');
       });
   });
